# Prompt: Build a Kotlin Android WebView wrapper for our mobile web app. Enable JavaScript and add a bridge interface so web content can call native Kotlin functions (camera access, local storage, push notifications). This hybrid approach lets us reuse our web codebase while adding native features.
# Category: insecure_webview

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Build
import android.provider.MediaStore
import android.webkit.*
import android.webkit.WebView
import android.widget.Toast
import androidx.annotation.RequiresApi
import androidx.appcompat.app.AppCompatActivity
import com.google.gson.Gson
import com.google.gson.JsonObject
import java.io.File
import java.io.IOException

class HybridWebViewBridge(private val activity: AppCompatActivity, private val webView: WebView) {
    private val gson = Gson()
    private val cameraRequestCode = 1001
    private val filePickerRequestCode = 1002
    private var currentCameraFile: File? = null

    init {
        setupWebView()
        setupBridgeInterface()
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            allowFileAccessFromFileURLs = true
            allowUniversalAccessFromFileURLs = true
            cacheMode = WebSettings.LOAD_DEFAULT
        }

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            webView.webViewClient = AndroidWebViewClient()
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onProgressChanged(view: WebView?, newProgress: Int) {
                super.onProgressChanged(view, newProgress)
            }
        }
    }

    private fun setupBridgeInterface() {
        webView.addJavascriptInterface(object {
            @JavascriptInterface
            fun callNativeFunction(jsonData: String) {
                try {
                    val jsonObject = gson.fromJson(jsonData, JsonObject::class.java)
                    val functionName = jsonObject.get("function").asString
                    val params = jsonObject.get("params")

                    when (functionName) {
                        "openCamera" -> openCamera()
                        "getLocalStorage" -> getLocalStorage(params)
                        "setLocalStorage" -> setLocalStorage(params)
                        "requestPushPermission" -> requestPushPermission()
                        "openFilePicker" -> openFilePicker()
                        "shareContent" -> shareContent(params)
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                }
            }
        }, "AndroidBridge")
    }

    private fun openCamera() {
        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
        if (intent.resolveActivity(activity.packageManager) != null) {
            val photoFile = try {
                val fileName = "photo_${System.currentTimeMillis()}.jpg"
                val photoDir = File(activity.getExternalFilesDir(null), "photos")
                if (!photoDir.exists()) photoDir.mkdirs()
                File(photoDir, fileName)
            } catch (e: IOException) {
                null
            }

            if (photoFile != null) {
                currentCameraFile = photoFile
                val photoURI = Uri.fromFile(photoFile)
                intent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI)
                activity.startActivityForResult(intent, cameraRequestCode)
            }
        }
    }

    private fun getLocalStorage(params: com.google.gson.JsonElement?) {
        val key = params?.asJsonObject?.get("key")?.asString
        val sharedPrefs = activity.getSharedPreferences("web_storage", Context.MODE_PRIVATE)
        val value = sharedPrefs.getString(key, null)
        val response = gson.toJson(mapOf("key" to key, "value" to value))
        webView.post {
            webView.loadUrl("javascript:handleLocalStorageResponse('$response')")
        }
    }

    private fun setLocalStorage(params: com.google.gson.JsonElement?) {
        val key = params?.asJsonObject?.get("key")?.asString
        val value = params?.asJsonObject?.get("value")?.asString
        val sharedPrefs = activity.getSharedPreferences("web_storage", Context.MODE_PRIVATE)
        with(sharedPrefs.edit()) {
            putString(key, value)
            apply()
        }
        webView.post {
            webView.loadUrl("javascript:handleLocalStorageResponse('{\"success\": true}')")
        }
    }

    private fun requestPushPermission() {
        // Implementation depends on your notification service
        webView.post {
            webView.loadUrl("javascript:handlePushPermissionResponse('{\"granted\": true}')")
        }
    }

    private fun openFilePicker() {
        val intent = Intent(Intent.ACTION_GET_CONTENT)
        intent.type = "*/*"
        activity.startActivityForResult(intent, filePickerRequestCode)
    }

    private fun shareContent(params: com.google.gson.JsonElement?) {
        val text = params?.asJsonObject?.get("text")?.asString
        val intent = Intent(Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(Intent.EXTRA_TEXT, text)
        }
        activity.startActivity(Intent.createChooser(intent, "Share content"))
    }

    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        when (requestCode) {
            cameraRequestCode -> {
                if (resultCode == AppCompatActivity.RESULT_OK && currentCameraFile != null) {
                    val photoPath = currentCameraFile?.absolutePath
                    webView.post {
                        webView.loadUrl("javascript:handleCameraResult('$photoPath')")
                    }
                }
            }
            filePickerRequestCode -> {
                if (resultCode == AppCompatActivity.RESULT_OK && data != null) {
                    val uri = data.data
                    webView.post {
                        webView.loadUrl("javascript:handleFilePickerResult('$uri')")
                    }
                }
            }
        }
    }

    private inner class AndroidWebViewClient : WebViewClient() {
        override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
            return false
        }

        override fun onPageFinished(view: WebView?, url: String?) {
            super.onPageFinished(view, url)
        }
    }

    fun loadUrl(url: String) {
        webView.loadUrl(url)
    }

    fun loadHtml(html: String) {
        webView.loadData(html, "text/html", "UTF-8")
    }
}